import React, { useState, useEffect } from "react";
import { Form, Button, Col, Row } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Header from "../../components/Headers/Header";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    const [drug, setDrug] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_id: "",
        price: "",
        unit: "",
        description: "",
    });

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    // Fetch dữ liệu cũ
    useEffect(() => {
        fetchMedicine();
    }, []);

    const fetchMedicine = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
            const fetchedDrug = response.data;

            // Kiểm tra dữ liệu trả về có hợp lệ không
            if (!fetchedDrug) throw new Error("Dữ liệu không hợp lệ");

            setDrug({
                medicine_code: fetchedDrug.medicine_code || "",
                medicine_name: fetchedDrug.medicine_name || "",
                medicine_type_id: fetchedDrug.medicine_type_id?.toString() || "",
                price: fetchedDrug.price?.toString() || "",
                unit: fetchedDrug.unit || "",
                description: fetchedDrug.description || "",
            });
        } catch (error) {
            console.error("Lỗi khi lấy dữ liệu thuốc:", error);
            setError("Không tìm thấy thuốc hoặc có lỗi khi tải dữ liệu.");
        } finally {
            setLoading(false);
        }
    };

    // Xử lý nhập liệu
    const handleChange = (e) => {
        const { name, value } = e.target;
        setDrug({ ...drug, [name]: value });
    };

    // Xử lý mô tả
    const handleDescriptionChange = (value) => {
        setDrug({ ...drug, description: value });
    };

    // Xử lý lưu thay đổi
    const handleUpdate = async (e) => {
        e.preventDefault();

        // Kiểm tra nhập liệu
        if (!drug.medicine_code || !drug.medicine_name || !drug.medicine_type_id || !drug.price || !drug.unit) {
            alert("Vui lòng điền đầy đủ các trường bắt buộc!");
            return;
        }

        try {
            await axios.put(`http://localhost:5001/api/medicine/${id}`, {
                medicine_code: drug.medicine_code,
                medicine_name: drug.medicine_name,
                medicine_type_id: parseInt(drug.medicine_type_id, 10),
                price: parseFloat(drug.price),
                unit: drug.unit,
                description: drug.description,
            });

            alert("Cập nhật thành công!");
            navigate("/listOfDrugs"); // Điều hướng về danh sách thuốc
        } catch (error) {
            console.error("Lỗi khi cập nhật thuốc:", error);
            alert(`Cập nhật thất bại! Lỗi: ${error.response?.data?.message || error.message}`);
        }
    };

    const handleCancel = () => {
        navigate("/listOfDrugs");
    };

    if (loading) return <p>Đang tải dữ liệu...</p>;
    if (error) return <p style={{ color: "red" }}>{error}</p>;

    return (
        <>
            <Header />
            <div className="container mt-4">
                <h4 className="mb-4" style={{ fontSize: "28px", fontWeight: "bold" }}>
                    Chỉnh sửa thuốc
                </h4>
                <Form onSubmit={handleUpdate}>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineCode">
                                <Form.Label>Mã thuốc *</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_code"
                                    value={drug.medicine_code}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="medicineName">
                                <Form.Label>Tên thuốc *</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_name"
                                    value={drug.medicine_name}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineTypeId">
                                <Form.Label>Loại thuốc *</Form.Label>
                                <Form.Control
                                    type="number"
                                    name="medicine_type_id"
                                    value={drug.medicine_type_id}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="drugPrice">
                                <Form.Label>Giá *</Form.Label>
                                <Form.Control
                                    type="number"
                                    name="price"
                                    value={drug.price}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="drugUnit">
                                <Form.Label>Đơn vị *</Form.Label>
                                <Form.Control
                                    type="text"
                                    name="unit"
                                    value={drug.unit}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>

                    <Form.Group controlId="drugDescription" className="mb-4">
                        <Form.Label>Mô tả *</Form.Label>
                        <ReactQuill
                            theme="snow"
                            value={drug.description}
                            onChange={handleDescriptionChange}
                            required
                        />
                    </Form.Group>

                    <div className="d-flex justify-content-end">
                        <Button variant="danger" onClick={handleCancel} className="me-2">
                            Quay lại
                        </Button>
                        <Button variant="primary" type="submit">
                            Lưu lại
                        </Button>
                    </div>
                </Form>
            </div>
        </>
    );
};

export default EditDrug;
